
.panel {
  display: grid;
  gap: 18px;
}

.panel-heading,
.identity-grid,
.resource-strip,
.ability-grid {
  display: grid;
  gap: 12px;
}

.panel-heading {
  grid-template-columns: 1fr auto;
  align-items: end;
}

.panel-kicker {
  margin: 0 0 6px;
  color: var(--dnd-accent);
  font-size: 11px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
}

h2,
.meta {
  margin: 0;
}

.meta {
  color: var(--dnd-text-soft);
}

.identity-grid,
.resource-strip,
.ability-grid {
  grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
}

label,
.resource-card,
.ability-card {
  display: grid;
  gap: 8px;
  padding: 14px;
  border: 1px solid var(--dnd-border-soft);
  background: var(--dnd-panel-soft);
}

label span,
.resource-card span,
.ability-name {
  color: var(--dnd-text-soft);
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.14em;
}

input,
textarea {
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(0, 0, 0, 0.18);
  color: var(--dnd-text);
  padding: 10px 12px;
}

.bar {
  height: 8px;
  background: rgba(0, 0, 0, 0.22);
}

.bar i {
  display: block;
  height: 100%;
  background: linear-gradient(90deg, #cf8f46, #e9ca77);
}

.resource-card strong,
.ability-card strong,
.ability-card em {
  font-family: var(--dnd-font-display);
}

.ability-card {
  place-items: center;
  text-align: center;
}

.ability-card strong {
  font-size: 28px;
}

.ability-card em {
  color: var(--dnd-accent);
  font-style: normal;
}

.wide-field {
  width: 100%;
}

@media (max-width: 720px) {
  .panel-heading {
    grid-template-columns: 1fr;
  }
}
