
.status-shell {
  width: min(1380px, 100%);
  margin: 0 auto;
  display: grid;
  gap: 16px;
  padding: 16px;
  color: var(--dnd-text);
}

.hero-strip,
.hero-copy,
.hero-stats,
.page-shell,
.page-grid,
.metric-grid,
.stacked-list,
.panel-card,
.note-card {
  display: grid;
}

.hero-strip,
.page-shell {
  border: 1px solid var(--dnd-border);
  background:
    radial-gradient(circle at top left, rgba(215, 169, 91, 0.14), transparent 30%),
    linear-gradient(135deg, rgba(69, 48, 33, 0.96), rgba(20, 16, 13, 0.98));
  box-shadow: var(--dnd-shadow);
}

.hero-strip {
  grid-template-columns: minmax(0, 1.2fr) minmax(0, 1fr);
  gap: 16px;
  padding: 20px;
}

.hero-copy {
  gap: 8px;
}

.eyebrow,
.stat-card label,
.metric-card span {
  margin: 0;
  color: var(--dnd-text-soft);
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.hero-copy strong {
  font-family: var(--dnd-font-display);
  font-size: clamp(26px, 4vw, 44px);
  line-height: 0.96;
}

.hero-copy span {
  color: var(--dnd-text-soft);
  font-size: 14px;
}

.scene-summary {
  width: min(58ch, 100%);
  margin: 4px 0 0;
  line-height: 1.7;
  color: rgba(244, 231, 206, 0.88);
}

.hero-stats,
.metric-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.stat-card,
.metric-card,
.note-card,
.panel-card {
  gap: 8px;
  padding: 14px;
  border: 1px solid var(--dnd-border-soft);
  background: rgba(8, 6, 5, 0.28);
}

.stat-card--accent {
  background: linear-gradient(180deg, rgba(131, 73, 37, 0.34), rgba(18, 11, 9, 0.38));
}

.stat-card strong,
.metric-card strong,
.note-card strong {
  font-family: var(--dnd-font-display);
}

.stat-card strong {
  font-size: 24px;
}

.stat-card span,
.note-card p,
.note-card small {
  color: var(--dnd-text-soft);
}

.progress-track {
  width: 100%;
  height: 7px;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.08);
}

.progress-track span {
  display: block;
  height: 100%;
  background: linear-gradient(90deg, #d06d43, #e3bc73);
}

.page-shell {
  gap: 12px;
  padding: 14px;
}

.page-grid {
  gap: 12px;
}

.stacked-list {
  gap: 10px;
}

.card-header h2,
.card-header p,
.note-card p,
.note-card small {
  margin: 0;
}

.note-head {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: baseline;
}

.bottom-nav {
  display: grid;
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: 10px;
  padding-top: 8px;
  border-top: 1px solid rgba(215, 169, 91, 0.16);
}

.dice-summary-card {
  gap: 12px;
}

.dice-summary-card .card-header {
  display: grid;
  gap: 6px;
}

.dice-summary-card .card-header p {
  color: var(--dnd-text-soft);
  line-height: 1.7;
}

.dice-metric-grid {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.embedded-panel {
  min-width: 0;
}

.nav-button {
  border: 1px solid rgba(215, 169, 91, 0.16);
  background: rgba(255, 255, 255, 0.03);
  color: var(--dnd-text-soft);
  padding: 12px 10px;
  cursor: pointer;
  transition:
    transform 160ms ease,
    border-color 160ms ease,
    background 160ms ease;
}

.nav-button--active {
  color: var(--dnd-text);
  border-color: rgba(215, 169, 91, 0.55);
  background: linear-gradient(180deg, rgba(215, 169, 91, 0.16), rgba(141, 79, 43, 0.2));
}

.nav-button:hover {
  transform: translateY(-1px);
}

@media (max-width: 1024px) {
  .hero-strip,
  .dice-metric-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 720px) {
  .status-shell {
    padding: 12px;
  }

  .hero-strip,
  .page-shell {
    padding: 14px;
  }

  .hero-stats,
  .metric-grid,
  .bottom-nav {
    grid-template-columns: 1fr;
  }
}
